import React, { useState, useRef, useEffect } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import {
  MapPin, Heart, Trash2, Tag, ChevronRight,
  ShoppingBag, CheckCircle2, XCircle, Info
} from 'lucide-react';
import { useCart } from '../hooks/usecart';
import { useWishlist } from '../hooks/useWishlist';

const CartPage = () => {
  const navigate = useNavigate();
  const { items, removeItem, changeQuantity, getCartTotal } = useCart();

  const wishlist = useWishlist() || {};

  const [pincode, setPincode] = useState('');
  const [pinStatus, setPinStatus] = useState(null);
  const [couponCode, setCouponCode] = useState('SUMMER26');
  const [isCouponApplied, setIsCouponApplied] = useState(true);

  // ==========================================
  // PREMIUM TOAST NOTIFICATION SYSTEM
  // ==========================================
  const [toast, setToast] = useState({ show: false, message: '', type: 'heart' });
  const toastTimer = useRef(null);

  const showToast = (message, type = 'heart') => {
    if (toastTimer.current) clearTimeout(toastTimer.current);
    setToast({ show: true, message, type });
    toastTimer.current = setTimeout(() => {
      setToast(prev => ({ ...prev, show: false }));
    }, 3000);
  };

  useEffect(() => {
    return () => {
      if (toastTimer.current) clearTimeout(toastTimer.current);
    };
  }, []);

  const handleCheckPincode = () => {
    if (!pincode) return;
    const isHyderabad = /^(500|501|502)\d{3}$/.test(pincode.trim());

    if (isHyderabad) {
      setPinStatus({ type: 'success', message: 'Delivery available in your area!' });
    } else {
      setPinStatus({ type: 'error', message: 'Delivery currently limited to Hyderabad.' });
    }
  };

  const handleSaveForLater = (item) => {
    if (wishlist.addItem) {
      wishlist.addItem(item.productId, item.variantId, item.name, item.price, item.image);
    } else if (wishlist.toggleItem) {
      wishlist.toggleItem(item);
    }
    removeItem(item.productId, item.variantId);
    showToast(`Moved ${item.name || 'item'} to your Wishlist`, 'heart');
  };

  // ==========================================
  // BULLETPROOF PRICE HELPERS (Prevents NaN)
  // ==========================================
  const getSafePrice = (item) => Number(item.price || item.finalPrice || item.variants?.[0]?.price) || 0;
  const getSafeMrp = (item) => {
    const mrp = Number(item.mrp || item.originalPrice);
    return mrp > 0 ? mrp : Math.round(getSafePrice(item) * 2.13) || 0;
  };

  const totalItems = items.reduce((acc, item) => acc + (item.quantity || 1), 0);
  const totalMrp = items.reduce((acc, item) => acc + (getSafeMrp(item) * (item.quantity || 1)), 0);
  const totalDiscountedPrice = items.reduce((acc, item) => acc + (getSafePrice(item) * (item.quantity || 1)), 0);

  const baseDiscount = Math.max(0, totalMrp - totalDiscountedPrice);
  const couponDiscount = isCouponApplied && items.length > 0 ? 10750 : 0;

  // Ensure finalPayable is always a valid number, never negative
  const finalPayableRaw = (getCartTotal ? getCartTotal() : totalDiscountedPrice) - couponDiscount;
  const finalPayable = isNaN(finalPayableRaw) ? 0 : Math.max(0, finalPayableRaw);
  const totalSavings = isNaN(baseDiscount + couponDiscount) ? 0 : baseDiscount + couponDiscount;

  if (items.length === 0) {
    return (
      <div className="bg-gray-50 min-h-[70vh] flex flex-col items-center justify-center px-4 py-16">
        <div className="bg-white p-8 md:p-12 rounded-2xl shadow-sm border border-gray-100 text-center max-w-lg w-full">
          <div className="w-20 h-20 md:w-24 md:h-24 bg-orange-50 rounded-full flex items-center justify-center mx-auto mb-6">
            <ShoppingBag size={36} className="text-[#f97316]" />
          </div>
          <h2 className="text-xl md:text-2xl font-bold text-gray-900 mb-3 tracking-tight">Your cart is empty</h2>
          <p className="text-sm md:text-base text-gray-500 mb-8">Looks like you haven't added any premium furniture to your cart yet.</p>
          <Link
            to="/"
            className="inline-block bg-[#f97316] text-white px-8 py-3.5 rounded-xl font-bold hover:bg-black transition-all duration-300 w-full tracking-wide shadow-md hover:shadow-black/20 active:scale-[0.98] outline-none focus:outline-none focus:ring-0 focus-visible:outline-none select-none"
          >
            START SHOPPING
          </Link>
        </div>
      </div>
    );
  }

  return (
    <div className="bg-[#f4f5f7] min-h-screen py-6 md:py-8 font-sans relative overflow-hidden">
      <div className={`fixed bottom-20 md:bottom-10 left-1/2 -translate-x-1/2 z-50 transition-all duration-500 ease-[cubic-bezier(0.175,0.885,0.32,1.275)] pointer-events-none w-[90%] md:w-auto flex justify-center ${toast.show ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-12 scale-90'}`}>
        <div className="bg-gray-900/95 backdrop-blur-md border border-gray-800 text-white px-5 py-3 rounded-full shadow-2xl flex items-center gap-3 w-full max-w-sm md:max-w-md">
          {toast.type === 'heart' ? (
            <div className="bg-orange-500/20 p-1.5 rounded-full shrink-0">
              <Heart size={14} className="text-[#f97316] fill-[#f97316]" />
            </div>
          ) : (
            <div className="bg-red-500/20 p-1.5 rounded-full shrink-0">
              <Info size={14} className="text-red-400" />
            </div>
          )}
          <span className="text-xs md:text-sm font-medium tracking-wide truncate">{toast.message}</span>
        </div>
      </div>

      <div className="container mx-auto px-4 max-w-6xl">
        <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 items-start">
          <div className="lg:col-span-8 flex flex-col gap-4">
            <div className="bg-white shadow-sm rounded-2xl overflow-hidden border border-gray-100">
              <div className="flex flex-col md:flex-row justify-between items-start md:items-center p-4 md:p-5 border-b border-gray-100 gap-4 md:gap-0">
                <h1 className="text-lg md:text-xl font-bold text-gray-900">
                  My Cart ({totalItems})
                </h1>

                <div className="flex flex-col items-start md:items-end gap-1 w-full md:w-auto">
                  <div className="flex flex-col sm:flex-row items-start sm:items-center gap-2 sm:gap-3 w-full md:w-auto">
                    <div className="flex items-center text-gray-600 shrink-0">
                      <MapPin size={18} className="mr-1" />
                      <span className="text-sm font-medium">Deliver To</span>
                    </div>
                    <div className={`flex items-center border rounded-lg overflow-hidden w-full sm:w-auto transition-all duration-300 ease-out ${pinStatus?.type === 'error' ? 'border-red-300 focus-within:ring-red-300' : pinStatus?.type === 'success' ? 'border-green-300 focus-within:ring-green-300' : 'border-gray-300 focus-within:border-orange-400 focus-within:ring-1 focus-within:ring-orange-400'}`}>
                      <input
                        type="text"
                        placeholder="Enter Pincode"
                        value={pincode}
                        maxLength={6}
                        onChange={(e) => {
                          setPincode(e.target.value);
                          if (pinStatus) setPinStatus(null);
                        }}
                        className="w-full sm:w-36 px-3 py-2 text-sm outline-none border-none bg-transparent focus:outline-none focus:ring-0"
                      />
                      <button
                        onClick={handleCheckPincode}
                        className="bg-transparent text-[#f97316] font-bold text-xs tracking-wide px-4 py-2 border-l border-gray-200 hover:bg-orange-50 active:bg-orange-100 transition-colors duration-200 outline-none focus:outline-none focus:ring-0 shrink-0 select-none"
                      >
                        CHECK
                      </button>
                    </div>
                  </div>

                  {pinStatus && (
                    <div className={`flex items-center gap-1 text-[11px] font-medium mt-1 ${pinStatus.type === 'success' ? 'text-green-600' : 'text-red-500'}`}>
                      {pinStatus.type === 'success' ? <CheckCircle2 size={12} /> : <XCircle size={12} />}
                      {pinStatus.message}
                    </div>
                  )}
                </div>
              </div>

              <div className="flex flex-col">
                {items.map((item, index) => {
                  const price = getSafePrice(item);
                  const mrp = getSafeMrp(item);

                  // STRICT MATH: Prevent division by zero if data is completely corrupted
                  const discountPercent = mrp > 0 && mrp > price ? Math.round(((mrp - price) / mrp) * 100) : 0;

                  return (
                    <div key={`${item.productId}_${item.variantId}_${index}`} className="group flex flex-col sm:flex-row p-4 sm:p-5 border-b border-gray-100 last:border-0 hover:bg-gray-50/80 transition-colors duration-300 ease-in-out">
                      <div className="shrink-0 mb-4 sm:mb-0 overflow-hidden rounded-xl border border-gray-200 bg-gray-100 w-full sm:w-32 h-48 sm:h-32">
                        <img
                          src={item.image || 'https://images.unsplash.com/photo-1555041469-a586c61ea9bc?w=800&q=80'}
                          alt={item.name || 'Product Image'}
                          className="w-full h-full object-cover transform transition-transform duration-500 ease-out group-hover:scale-[1.04]"
                          onError={(e) => {
                            e.target.onerror = null;
                            e.target.src = 'https://images.unsplash.com/photo-1493663284031-b7e3aefcae8e?w=800&q=80';
                          }}
                        />
                      </div>

                      <div className="sm:ml-6 flex-1 flex flex-col justify-between">
                        <div>
                          <h3 className="text-base font-semibold text-gray-900 tracking-tight leading-snug group-hover:text-[#f97316] transition-colors duration-300">
                            {item.name || 'Premium Furniture Item'}
                          </h3>
                          <p className="text-xs text-gray-500 mt-1 font-medium">Variant: {item.variantId || 'Default'}</p>

                          <div className="mt-4 flex flex-wrap items-center gap-x-6 gap-y-4">
                            <div className="flex items-center">
                              <span className="text-sm font-medium text-gray-700 mr-3 hidden sm:inline-block">Qty.</span>
                              <div className="flex items-center border border-gray-300 rounded-lg bg-white transition-colors duration-200 hover:border-gray-400 overflow-hidden">
                                <button
                                  onClick={() => { if (item.quantity > 1) { changeQuantity(item.productId, item.variantId, item.quantity - 1) } }}
                                  className="w-8 h-8 flex items-center justify-center text-gray-600 hover:bg-orange-50 hover:text-[#f97316] active:scale-90 transition-all duration-200 outline-none focus:outline-none focus:ring-0 select-none"
                                >
                                  -
                                </button>
                                <span className="w-10 h-8 flex items-center justify-center text-sm font-semibold border-x border-gray-200">
                                  {item.quantity || 1}
                                </span>
                                <button
                                  onClick={() => changeQuantity(item.productId, item.variantId, (item.quantity || 1) + 1)}
                                  className="w-8 h-8 flex items-center justify-center text-gray-600 hover:bg-orange-50 hover:text-[#f97316] active:scale-90 transition-all duration-200 outline-none focus:outline-none focus:ring-0 select-none"
                                >
                                  +
                                </button>
                              </div>
                            </div>

                            <div className="flex flex-col">
                              {discountPercent > 0 && (
                                <span className="text-[10px] sm:text-[11px] font-semibold tracking-wide text-[#22c55e] mb-0.5">Limited-Time Deal</span>
                              )}
                              <div className="flex items-baseline gap-2">
                                <span className="text-lg font-bold text-gray-900">₹{price.toLocaleString('en-IN')}</span>
                                {mrp > price && (
                                  <span className="text-xs sm:text-sm text-gray-400 line-through font-medium">₹{mrp.toLocaleString('en-IN')}</span>
                                )}
                                {discountPercent > 0 && (
                                  <span className="text-xs sm:text-sm font-bold text-[#22c55e]">{discountPercent}% OFF</span>
                                )}
                              </div>
                            </div>
                          </div>
                        </div>

                        <div className="flex items-center justify-between sm:justify-start gap-6 mt-5 pt-4 border-t border-gray-100 sm:border-0 sm:pt-0 sm:mt-auto text-sm font-semibold text-gray-500">
                          <button
                            onClick={() => handleSaveForLater(item)}
                            className="flex items-center gap-1.5 hover:text-[#f97316] transition-colors duration-200 outline-none focus:outline-none focus:ring-0 focus-visible:outline-none select-none group/btn"
                          >
                            <Heart size={16} className="group-hover/btn:fill-orange-50 transition-colors duration-200" />
                            Save For Later
                          </button>
                          <button
                            onClick={() => removeItem(item.productId, item.variantId)}
                            className="flex items-center gap-1.5 hover:text-red-500 transition-colors duration-200 outline-none focus:outline-none focus:ring-0 focus-visible:outline-none select-none"
                          >
                            <Trash2 size={16} />
                            Remove
                          </button>
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          <div className="lg:col-span-4 flex flex-col gap-4 md:sticky md:top-6">
            <div className="bg-white shadow-sm rounded-2xl p-4 md:p-5 border border-gray-100 hover:border-gray-200 transition-colors duration-300">
              <div className="flex flex-col gap-3">
                <div className="flex items-center justify-between cursor-pointer group">
                  <div className="flex items-center gap-2">
                    <Tag size={18} className="text-[#f97316] group-hover:scale-110 transition-transform duration-300" />
                    <span className="text-sm font-medium text-gray-800">
                      <span className="font-bold text-[#f97316]">LOGIN</span> to unlock coupons!
                    </span>
                  </div>
                  <ChevronRight size={18} className="text-gray-400 group-hover:text-[#f97316] group-hover:translate-x-1 transition-all duration-300" />
                </div>

                {isCouponApplied && (
                  <div className="flex items-start justify-between bg-green-50/50 p-3 md:p-4 rounded-xl border border-green-100 mt-2 transition-all duration-500 ease-in-out">
                    <div className="flex flex-col">
                      <span className="text-xs md:text-sm text-gray-800 font-medium">
                        Coupon Applied: <span className="font-bold">{couponCode}</span>
                      </span>
                      <span className="text-[11px] md:text-xs text-[#22c55e] font-medium mt-0.5">
                        You have saved ₹{couponDiscount.toLocaleString('en-IN')}
                      </span>
                    </div>
                    <button
                      onClick={() => setIsCouponApplied(false)}
                      className="text-[10px] md:text-xs font-bold text-[#f97316] border border-[#f97316] px-2.5 md:px-3 py-1 md:py-1.5 rounded-lg hover:bg-orange-50 active:bg-orange-100 transition-colors duration-200 outline-none focus:outline-none focus:ring-0 tracking-wide select-none"
                    >
                      CHANGE
                    </button>
                  </div>
                )}
              </div>
            </div>

            <div className="bg-white shadow-sm rounded-2xl border border-gray-100 hover:border-gray-200 transition-colors duration-300 flex flex-col overflow-hidden">
              <div className="p-4 md:p-5 border-b border-gray-100">
                <h3 className="text-base font-semibold text-gray-800">
                  Price Detail <span className="font-normal text-gray-500 text-sm">({totalItems} Items)</span>
                </h3>
              </div>

              <div className="p-4 md:p-5 space-y-4">
                <div className="flex justify-between items-center text-sm font-medium text-gray-700">
                  <span>MRP</span><span>₹{totalMrp.toLocaleString('en-IN')}</span>
                </div>
                <div className="flex justify-between items-center text-sm font-medium text-gray-700">
                  <span>Discount</span><span className="text-[#22c55e]">- ₹{baseDiscount.toLocaleString('en-IN')}</span>
                </div>
                {isCouponApplied && (
                  <div className="flex justify-between items-center text-sm font-medium text-gray-700">
                    <span>Coupon ({couponCode})</span><span className="text-[#22c55e]">- ₹{couponDiscount.toLocaleString('en-IN')}</span>
                  </div>
                )}
              </div>

              <div className="px-4 md:px-5 py-4 md:py-5 border-t border-gray-100 border-dashed bg-gray-50/50">
                <div className="flex justify-between items-start">
                  <span className="text-base font-semibold text-gray-900">Total Payable</span>
                  <div className="flex flex-col items-end">
                    <span className="text-lg md:text-xl font-bold text-gray-900">₹{finalPayable.toLocaleString('en-IN')}</span>
                    <span className="text-[10px] text-gray-500 mt-1">Inclusive of all taxes</span>
                  </div>
                </div>
              </div>

              {totalSavings > 0 && (
                <div className="p-3 md:p-4 bg-[#f0fdf4] border-t border-[#bbf7d0]">
                  <p className="text-xs md:text-sm font-medium text-[#166534] text-center">
                    Congratulations! You've Just saved ₹{totalSavings.toLocaleString('en-IN')} On Your Order.
                  </p>
                </div>
              )}
            </div>

            <div className="mt-2 flex flex-col gap-3 md:gap-4 mb-8 lg:mb-0">
              <p className="text-[11px] md:text-xs text-gray-500 text-center font-medium">EMI Starting ₹2,085/Month</p>
              <button
                onClick={() => {
                  if (pinStatus?.type === 'success' || pincode === '') {
                    navigate('/checkout');
                  } else {
                    showToast("Enter a valid Hyderabad pincode for delivery.", 'info');
                  }
                }}
                className="w-full bg-[#e87831] text-white py-3.5 md:py-4 rounded-xl font-bold tracking-wide hover:bg-black hover:shadow-lg hover:shadow-black/20 active:scale-[0.98] transform transition-all duration-300 outline-none focus:outline-none focus:ring-0 focus-visible:outline-none select-none"
              >
                PLACE ORDER
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CartPage;
